from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
from datetime import datetime

app = Flask(__name__)

# MongoDB connection
MONGO_URI = "mongodb://localhost:27017/"
client = MongoClient(MONGO_URI)
db = client.cms_db # Database name for the CMS

# Collections
users_collection = db.users
documents_collection = db.documents

# Ensure unique indexes for user-related fields
users_collection.create_index("username", unique=True)
users_collection.create_index("email", unique=True)

# Helper function to convert ObjectId to string for JSON serialization
def serialize_doc(doc):
    if not doc:
        return None
    doc['_id'] = str(doc['_id'])
    if 'author_id' in doc and isinstance(doc['author_id'], ObjectId):
        doc['author_id'] = str(doc['author_id'])
    return doc

# --- User Profile Endpoints ---

@app.route('/users', methods=['POST'])
def create_user():
    """
    Creates a new user profile.
    Requires: username, email (JSON body).
    """
    user_data = request.json
    username = user_data.get('username')
    email = user_data.get('email')

    if not username or not email:
        return jsonify({"error": "Username and email are required"}), 400

    if users_collection.find_one({"username": username}):
        return jsonify({"error": "Username already exists"}), 409
    if users_collection.find_one({"email": email}):
        return jsonify({"error": "Email already exists"}), 409

    user_data['created_at'] = datetime.utcnow()
    try:
        result = users_collection.insert_one(user_data)
        new_user = users_collection.find_one({"_id": result.inserted_id})
        return jsonify(serialize_doc(new_user)), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    """
    Retrieves a single user profile by ID.
    """
    try:
        user = users_collection.find_one({"_id": ObjectId(user_id)})
        if user:
            return jsonify(serialize_doc(user)), 200
        return jsonify({"error": "User not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

@app.route('/users', methods=['GET'])
def get_all_users():
    """
    Retrieves all user profiles.
    """
    users = list(users_collection.find())
    return jsonify([serialize_doc(user) for user in users]), 200

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    """
    Updates an existing user profile by ID.
    Allows updating username, email, etc. (JSON body).
    """
    user_data = request.json
    try:
        # Prevent updating unique fields if they already exist for another user
        if 'username' in user_data:
            existing_user = users_collection.find_one({"username": user_data['username'], "_id": {"$ne": ObjectId(user_id)}})
            if existing_user:
                return jsonify({"error": "Username already taken by another user"}), 409
        if 'email' in user_data:
            existing_user = users_collection.find_one({"email": user_data['email'], "_id": {"$ne": ObjectId(user_id)}})
            if existing_user:
                return jsonify({"error": "Email already taken by another user"}), 409

        result = users_collection.update_one(
            {"_id": ObjectId(user_id)},
            {"$set": user_data}
        )
        if result.matched_count:
            updated_user = users_collection.find_one({"_id": ObjectId(user_id)})
            return jsonify(serialize_doc(updated_user)), 200
        return jsonify({"error": "User not found"}), 404
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    """
    Deletes a user profile by ID.
    Prevents deletion if user has associated documents.
    """
    try:
        # Check if user has associated documents before deleting
        if documents_collection.find_one({"author_id": ObjectId(user_id)}):
            return jsonify({"error": "Cannot delete user with associated documents"}), 409

        result = users_collection.delete_one({"_id": ObjectId(user_id)})
        if result.deleted_count:
            return jsonify({"message": "User deleted successfully"}), 200
        return jsonify({"error": "User not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

# --- Document Endpoints ---

@app.route('/documents', methods=['POST'])
def create_document():
    """
    Creates a new content document.
    Requires: title, content, author_id (JSON body).
    Optional: tags (list of strings), status (string, default 'draft').
    """
    doc_data = request.json
    title = doc_data.get('title')
    content = doc_data.get('content')
    author_id = doc_data.get('author_id')
    tags = doc_data.get('tags', [])
    status = doc_data.get('status', 'draft') # Default status

    if not title or not content or not author_id:
        return jsonify({"error": "Title, content, and author_id are required"}), 400

    try:
        # Validate author_id exists
        if not users_collection.find_one({"_id": ObjectId(author_id)}):
            return jsonify({"error": "Author not found"}), 404

        doc_data['author_id'] = ObjectId(author_id)
        doc_data['tags'] = tags
        doc_data['status'] = status
        doc_data['created_at'] = datetime.utcnow()
        doc_data['updated_at'] = datetime.utcnow()

        result = documents_collection.insert_one(doc_data)
        new_doc = documents_collection.find_one({"_id": result.inserted_id})
        return jsonify(serialize_doc(new_doc)), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    """
    Retrieves a single document by ID.
    """
    try:
        document = documents_collection.find_one({"_id": ObjectId(doc_id)})
        if document:
            return jsonify(serialize_doc(document)), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid Document ID format"}), 400

@app.route('/documents', methods=['GET'])
def query_documents():
    """
    Queries documents based on various criteria.
    Query parameters:
    - author_id: Filter by author.
    - tags: Comma-separated list of tags (documents must have at least one of these tags).
    - status: Filter by document status ('draft', 'published', 'archived').
    - search_term: Fuzzy search in title and content.
    """
    query_params = request.args
    query = {}

    author_id = query_params.get('author_id')
    if author_id:
        try:
            query['author_id'] = ObjectId(author_id)
        except Exception:
            return jsonify({"error": "Invalid author_id format"}), 400

    tags = query_params.get('tags') # Example: ?tags=python,flask
    if tags:
        query['tags'] = {"$in": tags.split(',')}

    status = query_params.get('status') # Example: ?status=published
    if status:
        query['status'] = status

    search_term = query_params.get('search_term') # Example: ?search_term=database
    if search_term:
        query["$or"] = [
            {"title": {"$regex": search_term, "$options": "i"}}, # Case-insensitive title search
            {"content": {"$regex": search_term, "$options": "i"}} # Case-insensitive content search
        ]

    documents = list(documents_collection.find(query))
    return jsonify([serialize_doc(doc) for doc in documents]), 200

@app.route('/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """
    Updates an existing document by ID.
    Allows updating title, content, author_id, tags, status (JSON body).
    """
    doc_data = request.json
    try:
        if 'author_id' in doc_data:
            # Ensure the new author_id is valid if provided
            if not users_collection.find_one({"_id": ObjectId(doc_data['author_id'])}):
                return jsonify({"error": "New author not found"}), 404
            doc_data['author_id'] = ObjectId(doc_data['author_id']) # Convert to ObjectId

        doc_data['updated_at'] = datetime.utcnow() # Update timestamp on modification

        result = documents_collection.update_one(
            {"_id": ObjectId(doc_id)},
            {"$set": doc_data}
        )
        if result.matched_count:
            updated_doc = documents_collection.find_one({"_id": ObjectId(doc_id)})
            return jsonify(serialize_doc(updated_doc)), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """
    Deletes a document by ID.
    """
    try:
        result = documents_collection.delete_one({"_id": ObjectId(doc_id)})
        if result.deleted_count:
            return jsonify({"message": "Document deleted successfully"}), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid Document ID format"}), 400

# --- Aggregation Pipelines ---

@app.route('/analytics/documents_by_author', methods=['GET'])
def documents_by_author():
    """
    Aggregation pipeline: Counts documents published by each author.
    Joins with the users collection to get author details.
    """
    pipeline = [
        {"$group": {"_id": "$author_id", "count": {"$sum": 1}}},
        {"$lookup": {
            "from": "users", # The collection to join with
            "localField": "_id", # Field from the input documents (from $group)
            "foreignField": "_id", # Field from the "users" documents
            "as": "author_info" # Output array field
        }},
        {"$unwind": "$author_info"}, # Deconstruct the author_info array field
        {"$project": {
            "_id": 0, # Exclude default _id
            "author_id": "$_id",
            "username": "$author_info.username",
            "email": "$author_info.email",
            "document_count": "$count"
        }},
        {"$sort": {"document_count": -1}} # Sort by count descending
    ]
    results = list(documents_collection.aggregate(pipeline))
    # Serialize ObjectId for author_id if it's still present
    for res in results:
        if 'author_id' in res and isinstance(res['author_id'], ObjectId):
            res['author_id'] = str(res['author_id'])
    return jsonify(results), 200

@app.route('/analytics/popular_tags', methods=['GET'])
def popular_tags():
    """
    Aggregation pipeline: Finds the most popular tags across all documents.
    Returns top 10 tags.
    """
    pipeline = [
        {"$unwind": "$tags"}, # Deconstructs the tags array field
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}}, # Group by tag and count
        {"$sort": {"count": -1}}, # Sort by count descending
        {"$limit": 10} # Limit to top 10
    ]
    results = list(documents_collection.aggregate(pipeline))
    # Rename _id to tag for clarity
    for res in results:
        res['tag'] = res.pop('_id')
    return jsonify(results), 200

@app.route('/analytics/document_status_distribution', methods=['GET'])
def document_status_distribution():
    """
    Aggregation pipeline: Shows the distribution of documents by their status.
    """
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}}, # Group by status and count
        {"$project": {
            "_id": 0, # Exclude default _id
            "status": "$_id",
            "count": 1
        }}
    ]
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

if __name__ == '__main__':
    app.run(debug=True, port=5000)